<template>
  <div class="istalist">
    <van-sticky>
      <van-nav-bar
        title="委托单列表"
        left-arrow
        @click-left="onClickLeft"
        @click-right="onClickRight"
      />
    </van-sticky>
    <ul class="list">
      <li class="item" v-for="(item, i) in itemlist" :key="i">
        <Istadetail :detail="item" :index="i"></Istadetail>
      </li>
    </ul>

    <van-row>
      <van-col span="24" class="istalist_jia">
        <van-button
          style="width: 44px"
          @click="addsample"
          icon="plus"
          type="primary"
          round
      /></van-col>
    </van-row>
    <div class="istalist_fix">
      <van-button round block type="info" @click="onsub">发起委托</van-button>
    </div>
    <div class="istalist_bottom"></div>
  </div>
</template>
<script>
import Istadetail from "../../components/Istadetail.vue";
import Istacard from "../../components/Istacard.vue";
import { Dialog } from "vant";
import { Toast } from 'vant';
import { postcun } from "../../utils/http/api";
import { mapState } from "vuex";
export default {
  components: {
    Istadetail,
    Istacard,
  },
  data() {
    return {
      itemlist: [],
    };
  },
  name: "istalist",
  created() {
    this.itemlist = JSON.parse(localStorage.getItem("sampleList"));
  },
  computed: {
    ...mapState(["userid", "adminId"]),
  },
  methods: {
    onsub() {
      let data = JSON.parse(localStorage.getItem("sampleList"));
      if (data.length === 0) {
        Toast("至少添加一种产品!");
      } else {
        Dialog.confirm({
          title: "是否发起委托？",
          message: "",
          beforeClose: (action, done) => {
            // console.log(action);
            if (action === "confirm") {
              this.commit().then((res) => {
                console.log(res);
                if (res.data.code === 200) {
                  this.$router.push({
                    name: "qrcode",
                    query: { code: res.data.data, success: true },
                  });
                } else {
                  Toast(res.data.msg);
                }
                done();
              });
            } else {
              done();
            }
          },
        });
      }
    },
    commit() {
      let the = this;
      let entrustInfo = JSON.parse(localStorage.getItem("entrustInfo"));
      Object.assign(entrustInfo, {
        entrustType:
          entrustInfo.entrustType === "客户委托"
            ? 1
            : entrustInfo.entrustType === "内部委托"
            ? 2
            : 3,
        acceptUserId: the.userid,
        crm: the.adminId,
      });
      let sampleList = JSON.parse(localStorage.getItem("sampleList"));
      return postcun(entrustInfo, sampleList);
    },
    onClickLeft() {
      this.$router.go(-1);
    },
    onClickRight() {},
    addsample() {
      this.$router.push({ name: "sample" });
    },
  },
};
</script>
<style lang="less">
.istalist {
  width: 7.5rem;
  height: 13.34rem;
  background: @gray-2;
  overflow-y: scroll;
  // padding-bottom: 2rem;
  .list {
    .item {
      display: flex;
      align-items: center;
      justify-items: center;
    }
  }
}
.istalist_jia {
  margin-top: 0.2rem;
  display: flex;
  flex-wrap: wrap;
  align-items: center;

  justify-content: center;

  flex-direction: column-reverse;
}
.istalist_fix {
  position: fixed;
  bottom: 0px;
  background: @gray-1;
  width: 7.5rem;
  padding: 0.32rem;
  box-sizing: border-box;
}
.istalist_bottom {
  width: 100%;
  height: 3rem;
  background: @gray-2;
}
</style>